# Contact book using list of dictionaries
contacts = [
    {
        'name': 'Alice Johnson',
        'phone': '555-0123',
        'email': 'alice@email.com',
        'tags': {'friend', 'work'}
    },
    {
        'name': 'Bob Smith',
        'phone': '555-0456',
        'email': 'bob@email.com',
        'tags': {'family'}
    },
    {
        'name': 'Carol White',
        'phone': '555-0789',
        'email': 'carol@email.com',
        'tags': {'friend', 'school'}
    }
]

print('📱 Contact Book')
print('=' * 50)

# Display all contacts
for contact in contacts:
    print(f"\n{contact['name']}")
    print(f"  Phone: {contact['phone']}")
    print(f"  Email: {contact['email']}")
    print(f"  Tags: {', '.join(contact['tags'])}")

# Search by name
def find_contact(name):
    for contact in contacts:
        if name.lower() in contact['name'].lower():
            return contact
    return None

print('\n' + '=' * 50)
print('SEARCH RESULTS:')
search_result = find_contact('bob')
if search_result:
    print(f"Found: {search_result['name']}")
    print(f"Phone: {search_result['phone']}")

# Find all contacts with specific tag
def find_by_tag(tag):
    return [c for c in contacts if tag in c['tags']]

friends = find_by_tag('friend')
print(f'\nFriends: {len(friends)} contacts')
for friend in friends:
    print(f"  - {friend['name']}")

# Statistics
all_tags = set()
for contact in contacts:
    all_tags.update(contact['tags'])

print(f'\nTotal contacts: {len(contacts)}')
print(f'Unique tags: {all_tags}')

